#include<bits/stdc++.h>
using namespace std;
long long n,k,dp[1010][1010],a[1010];
long long dfs(int x,int y)
{
    if(dp[x][y]!=-1)
    {
        return dp[x][y];
    }
    int now=(k>>x);
    if(now==1)
    {
        dp[x][y]=0;
        for(int i=1;i<=n;i++)
        {
            dp[x][y]^=(a[i]+y);
        }
        return dp[x][y];
    }
    dp[x][y]=0;
    if(now%2==0)
    {
        dp[x][y]=dfs(x+1,y/2)*2+((n%2)&(y%2));
    }
    else
    {
        for(int i=1;i<=n;i++)
        {
            dp[x][y]^=dfs(x+1,(y+a[i])/2)*2+(((y+a[i])%2)&(n%2));
        }
    }
    return dp[x][y];
}
int main()
{
    memset(dp,-1,sizeof(dp));
    scanf("%lld%lld",&n,&k);
    for(int i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    printf("%lld",dfs(0,0));
    return 0;
}
